import { create } from 'zustand';
import { FaceProfile } from '../types';

interface FaceState {
  faces: FaceProfile[];
  addFace: (face: Omit<FaceProfile, 'id'>) => void;
  updateFace: (face: FaceProfile) => void;
  deleteFace: (id: string) => void;
}

const initialFaces: FaceProfile[] = [
    { id: '1', name: 'Jane Smith', relation: 'Daughter', imageUrl: 'https://picsum.photos/seed/jane/400/400', notes: 'Visits every Sunday. She loves bringing you tulips.'},
    { id: '2', name: 'Dr. Emily White', relation: 'Doctor', imageUrl: 'https://picsum.photos/seed/emily/400/400', notes: 'Your primary physician. She is very kind.'},
    { id: '3', name: 'Mike Johnson', relation: 'Grandson', imageUrl: 'https://picsum.photos/seed/mike/400/400', notes: 'Loves to play chess and talk about space.'},
];

export const useFaceStore = create<FaceState>((set) => ({
  faces: initialFaces,
  addFace: (faceData) => {
    const newFace: FaceProfile = {
      id: `face-${Date.now()}`,
      ...faceData,
    };
    set((state) => ({ faces: [newFace, ...state.faces] }));
  },
  updateFace: (updatedFace) => {
    set((state) => ({
      faces: state.faces.map((f) => (f.id === updatedFace.id ? updatedFace : f)),
    }));
  },
  deleteFace: (id) => {
    set((state) => ({
      faces: state.faces.filter((f) => f.id !== id),
    }));
  },
}));

