const CaretakerRegisterPage: React.FC = () => {
  const navigate = useNavigate();
  const { addUser, findUserByPatientCode } = useUserStore();
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [patientCode, setPatientCode] = useState('');
  const [error, setError] = useState('');

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    setTimeout(() => {
      const patient = findUserByPatientCode(patientCode.toUpperCase());
      if (!patient) {
        setError('This ID does not exist. Please check with the patient.');
        setLoading(false);
        return;
      }

      addUser({
        name,
        email,
        role: UserRole.CARETAKER,
        patientId: patient.id,
      });

      setIsSubmitted(true);
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen relative flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8 overflow-hidden">
      {/* Blurred Background Image Overlay */}
      <div 
        className="absolute inset-0 z-0 bg-cover bg-center bg-no-repeat scale-110 blur-sm"
        style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=2029&auto=format&fit=crop")' }}
      >
        <div className="absolute inset-0 bg-white/40"></div>
      </div>

      <div className="max-w-md w-full p-10 glass-card relative z-10 border border-white/60 shadow-2xl">
        <AnimatePresence mode="wait">
          {!isSubmitted ? (
            <CaretakerForm
              handleRegister={handleRegister}
              name={name}
              setName={setName}
              email={email}
              setEmail={setEmail}
              password={password}
              setPassword={setPassword}
              patientCode={patientCode}
              setPatientCode={setPatientCode}
              error={error}
              loading={loading}
              navigate={navigate}
            />
          ) : (
            <CaretakerSuccess navigate={navigate} />
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

