                {!alert.isRead && (
                     <Button onClick={() => markAsRead(alert.id)} className="bg-white/80 hover:bg-white text-current text-sm px-4 py-2 rounded-xl">Got it</Button>
                )}
            </div>
        </div>
    );
}

