import { create } from 'zustand';
import { Reminder } from '../types';
import { db } from '../lib/firebase';
import { collection, addDoc, onSnapshot, query, where, deleteDoc, doc, updateDoc } from 'firebase/firestore';
import { useAuthStore } from './authStore';

interface ReminderState {
  reminders: (Reminder & { notified?: boolean })[];
  addReminder: (reminder: Omit<Reminder, 'id'>) => Promise<void>;
  markAsCompleted: (id: string) => Promise<void>;
  markAsNotified: (id: string) => Promise<void>;
  deleteReminder: (id: string) => Promise<void>;
  getDueReminder: () => (Reminder & { notified?: boolean }) | undefined;
  init: () => () => void;
}

export const useReminderStore = create<ReminderState>((set, get) => ({
  reminders: [],
  addReminder: async (data) => {
    const user = useAuthStore.getState().user;
    if (!user) return;
    const targetId = user.role === 'patient' ? user.id : user.patientId;
    await addDoc(collection(db, 'reminders'), {
      ...data,
      ownerId: targetId,
      notified: false,
      createdAt: new Date().toISOString()
    });
  },
  markAsCompleted: async (id) => {
    await updateDoc(doc(db, 'reminders', id), { isCompleted: true });
  },
  markAsNotified: async (id) => {
    await updateDoc(doc(db, 'reminders', id), { notified: true });
  },
  deleteReminder: async (id) => {
    await deleteDoc(doc(db, 'reminders', id));
  },
  getDueReminder: () => {
    const now = new Date();
    return get().reminders.find(r => {
        const [time, modifier] = r.time.split(' ');
        let [hours, minutes] = time.split(':').map(Number);
        if (modifier === 'PM' && hours < 12) hours += 12;
        if (modifier === 'AM' && hours === 12) hours = 0;
        const reminderTime = new Date();
        reminderTime.setHours(hours, minutes, 0, 0);
        return !r.isCompleted && !r.notified && reminderTime <= now;
    });
  },
  init: () => {
    const user = useAuthStore.getState().user;
    if (!user) return () => {};
    const targetId = user.role === 'patient' ? user.id : user.patientId;

    const q = query(collection(db, 'reminders'), where('ownerId', '==', targetId));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Reminder & { notified?: boolean }));
      set({ reminders: data });
    });
    return unsubscribe;
  }
}));

import { create } from 'zustand';
import { Alert } from '../types';
import { db } from '../lib/firebase';
import { collection, addDoc, onSnapshot, query, where, doc, updateDoc, orderBy } from 'firebase/firestore';
import { useAuthStore } from './authStore';

interface AlertState {
  alerts: Alert[];
  addAlert: (alertData: Omit<Alert, 'id' | 'timestamp' | 'isRead'>) => Promise<void>;
  markAsRead: (id: string) => Promise<void>;
  markAllAsRead: () => Promise<void>;
  init: () => () => void;
}

export const useAlertStore = create<AlertState>((set) => ({
  alerts: [],
  addAlert: async (alertData) => {
    const user = useAuthStore.getState().user;
    if (!user) return;
    const targetId = user.role === 'patient' ? user.id : user.patientId;
    await addDoc(collection(db, 'alerts'), {
      ...alertData,
      ownerId: targetId,
      timestamp: new Date().toISOString(),
      isRead: false
    });
  },
  markAsRead: async (id) => {
    await updateDoc(doc(db, 'alerts', id), { isRead: true });
  },
  markAllAsRead: async () => {
    const alerts = useAlertStore.getState().alerts;
    const promises = alerts.map(a => !a.isRead ? updateDoc(doc(db, 'alerts', a.id), { isRead: true }) : Promise.resolve());
    await Promise.all(promises);
  },
  init: () => {
    const user = useAuthStore.getState().user;
    if (!user) return () => {};
    const targetId = user.role === 'patient' ? user.id : user.patientId;

    const q = query(
      collection(db, 'alerts'), 
      where('ownerId', '==', targetId),
      orderBy('timestamp', 'desc')
    );
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Alert));
      set({ alerts: data });
    });
    return unsubscribe;
  }
}));

import { create } from 'zustand';
import { SafeZone } from '../types';
import { db } from '../lib/firebase';
import { doc, onSnapshot, setDoc, updateDoc, collection, addDoc, query, where, deleteDoc } from 'firebase/firestore';
import { useAuthStore } from './authStore';

interface GpsState {
  patientLocation: {
    location: { lat: number, lng: number };
    timestamp: string;
  };
  safeZones: SafeZone[];
  updatePatientLocation: (location: { lat: number, lng: number }) => Promise<void>;
  addSafeZone: (zoneData: Omit<SafeZone, 'id'>) => Promise<void>;
  updateSafeZone: (zoneData: SafeZone) => Promise<void>;
  deleteSafeZone: (id: string) => Promise<void>;
  init: () => () => void;
}

export const useGpsStore = create<GpsState>((set) => ({
    patientLocation: {
        location: { lat: 34.0522, lng: -118.2437 },
        timestamp: new Date().toISOString(),
    },
    safeZones: [],
    updatePatientLocation: async (location) => {
        const user = useAuthStore.getState().user;
        if (!user || user.role !== 'patient') return;
        const timestamp = new Date().toISOString();
        await setDoc(doc(db, 'locations', user.id), { location, timestamp });
    },
    addSafeZone: async (zoneData) => {
        const user = useAuthStore.getState().user;
        if (!user) return;
        const targetId = user.role === 'patient' ? user.id : user.patientId;
        await addDoc(collection(db, 'safeZones'), { ...zoneData, ownerId: targetId });
    },
    updateSafeZone: async (zoneData) => {
        const { id, ...data } = zoneData;
        await updateDoc(doc(db, 'safeZones', id), data);
    },
    deleteSafeZone: async (id) => {
        await deleteDoc(doc(db, 'safeZones', id));
    },
    init: () => {
        const user = useAuthStore.getState().user;
        if (!user) return () => {};
        const targetId = user.role === 'patient' ? user.id : user.patientId;

        // Listen to patient location
        const locUnsubscribe = onSnapshot(doc(db, 'locations', targetId), (docSnap) => {
            if (docSnap.exists()) {
                set({ patientLocation: docSnap.data() as any });
            }
        });

        // Listen to safe zones
        const szQuery = query(collection(db, 'safeZones'), where('ownerId', '==', targetId));
        const szUnsubscribe = onSnapshot(szQuery, (snapshot) => {
            const zones = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SafeZone));
            set({ safeZones: zones });
        });

        return () => {
            locUnsubscribe();
            szUnsubscribe();
        };
    }
}));

const haversineDistance = (coords1: {lat: number, lng: number}, coords2: {lat: number, lng: number}) => {
  const toRad = (x: number) => x * Math.PI / 180;
  const R = 6371e3;
  const dLat = toRad(coords2.lat - coords1.lat);
  const dLng = toRad(coords2.lng - coords1.lng);
  const lat1 = toRad(coords1.lat);
  const lat2 = toRad(coords2.lat);
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.sin(dLng / 2) * Math.sin(dLng / 2) * Math.cos(lat1) * Math.cos(lat2);
  return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
};

export const isOutsideZone = (location: {lat: number, lng: number}, zone: SafeZone) => {
    return haversineDistance(location, { lat: zone.lat, lng: zone.lng }) > zone.radius;
};

import { create } from 'zustand';
import { User, UserRole } from '../types';
import { db } from '../lib/firebase';
import { collection, query, where, getDocs, doc, setDoc, updateDoc } from 'firebase/firestore';

interface UserState {
  addUser: (uid: string, userData: Omit<User, 'id'>) => Promise<User>;
  updateUser: (updatedUser: User) => Promise<void>;
  findUserByPatientCode: (code: string) => Promise<User | undefined>;
}

export const useUserStore = create<UserState>((set) => ({
  addUser: async (uid, userData) => {
    const newUser: User = { id: uid, ...userData };
    await setDoc(doc(db, 'users', uid), newUser);
    return newUser;
  },
  updateUser: async (updatedUser) => {
    const { id, ...data } = updatedUser;
    await updateDoc(doc(db, 'users', id), data);
  },
  findUserByPatientCode: async (code: string) => {
    const q = query(
      collection(db, 'users'), 
      where('role', '==', UserRole.PATIENT), 
      where('patientCode', '==', code.toUpperCase())
    );
    const snapshot = await getDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as User;
    }
    return undefined;
  },
}));

