import { create } from 'zustand';
import { User, UserRole } from '../types';
import { auth, db } from '../lib/firebase';
// Fix: Use namespace import for Firebase Auth to resolve missing named exports errors
import * as FirebaseAuth from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';

interface AuthState {
  isAuthenticated: boolean;
  user: User | null;
  isLoading: boolean;
  login: (email: string, password: string) => Promise<boolean>;
  logout: () => Promise<void>;
  setUser: (user: User | null) => void;
  init: () => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  isAuthenticated: false,
  user: null,
  isLoading: true,
  setUser: (user) => set({ user, isAuthenticated: !!user, isLoading: false }),
  login: async (email, password) => {
    try {
      // Fix: Use FirebaseAuth namespace for signInWithEmailAndPassword
      const userCredential = await FirebaseAuth.signInWithEmailAndPassword(auth, email, password);
      const userDoc = await getDoc(doc(db, 'users', userCredential.user.uid));
      if (userDoc.exists()) {
        const userData = userDoc.data() as User;
        set({ user: userData, isAuthenticated: true });
        return true;
      }
      return false;
    } catch (error) {
      console.error("Login Error:", error);
      return false;
    }
  },
  logout: async () => {
    // Fix: Use FirebaseAuth namespace for signOut
    await FirebaseAuth.signOut(auth);
    set({ user: null, isAuthenticated: false });
  },
  init: () => {
    // Fix: Use FirebaseAuth namespace for onAuthStateChanged
    FirebaseAuth.onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const userDoc = await getDoc(doc(db, 'users', firebaseUser.uid));
        if (userDoc.exists()) {
          set({ user: userDoc.data() as User, isAuthenticated: true, isLoading: false });
        } else {
          set({ user: null, isAuthenticated: false, isLoading: false });
        }
      } else {
        set({ user: null, isAuthenticated: false, isLoading: false });
      }
    });
  },
}));

