export const listenToLocation = (uid: string, callback: (data: any) => void) => onSnapshot(doc(db, 'locations', uid), (d) => d.exists() && callback(d.data()));
export const listenToSafeZones = (targetId: string, callback: (zones: any[]) => void) => {
