};
export const addSafeZoneDoc = (data: any) => addDoc(collection(db, 'safeZones'), data);
export const updateSafeZoneDoc = (id: string, data: any) => updateDoc(doc(db, 'safeZones', id), data);
export const deleteSafeZoneDoc = (id: string) => deleteDoc(doc(db, 'safeZones', id));

import { create } from 'zustand';
import { User } from '../types';
import { loginUser, logoutUser, observeAuthState } from '../backend/auth';
import { getUserDoc } from '../backend/db';

interface AuthState {
  isAuthenticated: boolean;
  user: User | null;
  isLoading: boolean;
  login: (email: string, password: string) => Promise<boolean>;
  logout: () => Promise<void>;
  setUser: (user: User | null) => void;
  init: () => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  isAuthenticated: false,
  user: null,
  isLoading: true,
  setUser: (user) => set({ user, isAuthenticated: !!user, isLoading: false }),
  login: async (email, password) => {
    try {
      const userCredential = await loginUser(email, password);
      const userDoc = await getUserDoc(userCredential.user.uid);
      if (userDoc.exists()) {
        const userData = userDoc.data() as User;
        set({ user: userData, isAuthenticated: true });
        return true;
      }
      return false;
    } catch (error) {
      console.error("Login Error:", error);
      return false;
    }
  },
  logout: async () => {
    await logoutUser();
    set({ user: null, isAuthenticated: false });
  },
  init: () => {
    observeAuthState(async (firebaseUser) => {
      if (firebaseUser) {
        const userDoc = await getUserDoc(firebaseUser.uid);
        if (userDoc.exists()) {
          set({ user: userDoc.data() as User, isAuthenticated: true, isLoading: false });
        } else {
          set({ user: null, isAuthenticated: false, isLoading: false });
        }
      } else {
        set({ user: null, isAuthenticated: false, isLoading: false });
      }
    });
  },
}));

import { create } from 'zustand';
import { FaceProfile } from '../types';
import { useAuthStore } from './authStore';
import { listenToFaces, addFaceDoc, updateFaceDoc, deleteFaceDoc } from '../backend/db';

interface FaceState {
  faces: FaceProfile[];
  addFace: (face: Omit<FaceProfile, 'id'>) => Promise<void>;
  updateFace: (face: FaceProfile) => Promise<void>;
  deleteFace: (id: string) => Promise<void>;
  init: () => () => void;
}

export const useFaceStore = create<FaceState>((set) => ({
  faces: [],
  addFace: async (faceData) => {
    const user = useAuthStore.getState().user;
    if (!user) return;
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    await addFaceDoc({ ...faceData, ownerId: targetId });
  },
  updateFace: async (updatedFace) => {
    const { id, ...data } = updatedFace;
    await updateFaceDoc(id, data);
  },
  deleteFace: async (id) => {
    await deleteFaceDoc(id);
  },
  init: () => {
    const user = useAuthStore.getState().user;
    if (!user) return () => {};
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    return listenToFaces(targetId, (faces) => set({ faces }));
  },
}));

