    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (err: any) {
      // Map Firebase error codes to user-friendly messages
      let message = err.message || 'An error occurred during login.';
      if (err.code === 'auth/invalid-credential') {
        message = 'Invalid email or password. Please check your details.';
      } else if (err.code === 'auth/user-not-found') {
        message = 'No account found with this email.';
      } else if (err.code === 'auth/wrong-password') {
        message = 'Incorrect password.';
      } else if (message.includes('profile not found')) {
        message = 'Account exists but profile setup is incomplete. Try registering again.';
      }

      setError(message);
