import React, { useEffect } from 'react';
import { useAuthStore } from '../store/authStore';
import { useFaceStore } from '../store/faceStore';
import { useReminderStore } from '../store/reminderStore';
import { useAlertStore } from '../store/alertStore';
import { useGpsStore } from '../store/gpsStore';
import { useMemoryStore } from '../store/memoryStore';

/**
 * This component acts as the global orchestrator for data synchronization.
 * It listens for authentication changes and triggers the real-time listeners
 * for all functional modules (Faces, Reminders, GPS, etc.) only when a user is present.
 */
const FirebaseListener: React.FC = () => {
  const authInit = useAuthStore(state => state.init);
  const faceInit = useFaceStore(state => state.init);
  const reminderInit = useReminderStore(state => state.init);
  const alertInit = useAlertStore(state => state.init);
  const gpsInit = useGpsStore(state => state.init);
  const memoryInit = useMemoryStore(state => state.init);
  const user = useAuthStore(state => state.user);

  // 1. Initialize Authentication state immediately
  useEffect(() => {
    authInit();
  }, [authInit]);

  // 2. Once authenticated, initialize all data-sync listeners
  useEffect(() => {
    if (user) {
        console.log("Lucidia: User session detected. Starting real-time sync...");
        const unsubs = [
            faceInit(),
            reminderInit(),
            alertInit(),
            gpsInit(),
            memoryInit()
        ];

        // Clean up all listeners on logout or component unmount
        return () => {
            console.log("Lucidia: Cleaning up data listeners...");
            unsubs.forEach(u => u && u());
        };
    }
  }, [user, faceInit, reminderInit, alertInit, gpsInit, memoryInit]);

  return null; // This component has no UI, it just manages side-effects.
};

export default FirebaseListener;

