}));

import { create } from 'zustand';
import { Reminder } from '../types';
import { useAuthStore } from './authStore';
import { listenToReminders, addReminderDoc, updateReminderDoc, deleteReminderDoc } from '../../backend/db';

interface ReminderState {
  reminders: (Reminder & { notified?: boolean })[];
  addReminder: (reminder: Omit<Reminder, 'id'>) => Promise<void>;
  markAsCompleted: (id: string) => Promise<void>;
  markAsNotified: (id: string) => Promise<void>;
  deleteReminder: (id: string) => Promise<void>;
  getDueReminder: () => (Reminder & { notified?: boolean }) | undefined;
  init: () => () => void;
}

export const useReminderStore = create<ReminderState>((set, get) => ({
  reminders: [],
  addReminder: async (data) => {
    const user = useAuthStore.getState().user;
    if (!user) return;
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    await addReminderDoc({ ...data, ownerId: targetId });
  },
  markAsCompleted: async (id) => {
    await updateReminderDoc(id, { isCompleted: true });
  },
  markAsNotified: async (id) => {
    await updateReminderDoc(id, { notified: true });
  },
  deleteReminder: async (id) => {
    await deleteReminderDoc(id);
  },
  getDueReminder: () => {
    const now = new Date();
    return get().reminders.find(r => {
        const [time, modifier] = r.time.split(' ');
        let [hours, minutes] = time.split(':').map(Number);
        if (modifier === 'PM' && hours < 12) hours += 12;
        if (modifier === 'AM' && hours === 12) hours = 0;
        const reminderTime = new Date();
        reminderTime.setHours(hours, minutes, 0, 0);
        return !r.isCompleted && !r.notified && reminderTime <= now;
    });
  },
  init: () => {
    const user = useAuthStore.getState().user;
    if (!user) return () => {};
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    return listenToReminders(targetId, (reminders) => set({ reminders }));
  }
}));

import { create } from 'zustand';
import { Alert } from '../types';
import { useAuthStore } from './authStore';
import { listenToAlerts, addAlertDoc, updateAlertDoc } from '../../backend/db';

interface AlertState {
  alerts: Alert[];
  addAlert: (alertData: Omit<Alert, 'id' | 'timestamp' | 'isRead'>) => Promise<void>;
  markAsRead: (id: string) => Promise<void>;
  markAllAsRead: () => Promise<void>;
  init: () => () => void;
}

export const useAlertStore = create<AlertState>((set, get) => ({
  alerts: [],
  addAlert: async (alertData) => {
    const user = useAuthStore.getState().user;
    if (!user) return;
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    await addAlertDoc({ ...alertData, ownerId: targetId });
  },
  markAsRead: async (id) => {
    await updateAlertDoc(id, { isRead: true });
  },
  markAllAsRead: async () => {
    const alerts = get().alerts;
    const promises = alerts.map(a => !a.isRead ? updateAlertDoc(a.id, { isRead: true }) : Promise.resolve());
    await Promise.all(promises);
  },
  init: () => {
    const user = useAuthStore.getState().user;
    if (!user) return () => {};
    const targetId = user.role === 'patient' ? user.id : user.patientId!;
    return listenToAlerts(targetId, (alerts) => set({ alerts }));
  }
}));

import { create } from 'zustand';
import { SafeZone } from '../types';
import { useAuthStore } from './authStore';
import { 
  updateLocationDoc, 
  listenToLocation, 
  listenToSafeZones, 
  addSafeZoneDoc, 
  updateSafeZoneDoc, 
  deleteSafeZoneDoc 
} from '../../backend/db';

interface GpsState {
  patientLocation: {
    location: { lat: number, lng: number };
    timestamp: string;
  };
  safeZones: SafeZone[];
  updatePatientLocation: (location: { lat: number, lng: number }) => Promise<void>;
  addSafeZone: (zoneData: Omit<SafeZone, 'id'>) => Promise<void>;
  updateSafeZone: (zoneData: SafeZone) => Promise<void>;
  deleteSafeZone: (id: string) => Promise<void>;
  init: () => () => void;
}

export const useGpsStore = create<GpsState>((set, get) => ({
    patientLocation: {
        location: { lat: 34.0522, lng: -118.2437 },
        timestamp: new Date().toISOString(),
    },
    safeZones: [],
    updatePatientLocation: async (location) => {
        const user = useAuthStore.getState().user;
        if (!user || user.role !== 'patient') return;
        set({ patientLocation: { location, timestamp: new Date().toISOString() } });
        await updateLocationDoc(user.id, location);
    },
    addSafeZone: async (zoneData) => {
        const user = useAuthStore.getState().user;
        if (!user) return;
        const targetId = user.role === 'patient' ? user.id : user.patientId!;
        await addSafeZoneDoc({ ...zoneData, ownerId: targetId });
    },
    updateSafeZone: async (zoneData) => {
        const { id, ...data } = zoneData;
        await updateSafeZoneDoc(id, data);
    },
    deleteSafeZone: async (id) => {
        await deleteSafeZoneDoc(id);
    },
    init: () => {
        const user = useAuthStore.getState().user;
        if (!user) return () => {};
        const targetId = user.role === 'patient' ? user.id : user.patientId!;

        const szUnsubscribe = listenToSafeZones(targetId, (safeZones) => set({ safeZones }));
        const locUnsubscribe = listenToLocation(targetId, (data) => {
            if (data && data.location) {
                set({ patientLocation: data });
            }
        });

        return () => {
            szUnsubscribe();
            locUnsubscribe();
        };
    }
}));

export const isOutsideZone = (location: {lat: number, lng: number}, zone: SafeZone) => {
    const toRad = (x: number) => x * Math.PI / 180;
    const R = 6371e3;
    const dLat = toRad(zone.lat - location.lat);
    const dLng = toRad(zone.lng - location.lng);
    const lat1 = toRad(location.lat);
    const lat2 = toRad(zone.lat);
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.sin(dLng / 2) * Math.sin(dLng / 2) * Math.cos(lat1) * Math.cos(lat2);
    const dist = R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
    return dist > zone.radius;
};

