const PatientFacesView = () => {
    const { faces, addFace } = useFaceStore();
    const [isCameraOn, setIsCameraOn] = useState(false);
    const [status, setStatus] = useState<'idle' | 'recognizing' | 'recognized' | 'not-found' | 'saved'>('idle');
    const [recognizedFace, setRecognizedFace] = useState<FaceProfile | null>(null);
    const [capturedImage, setCapturedImage] = useState<string | null>(null);

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const recognitionTimeoutRef = useRef<number | null>(null);

    useEffect(() => {
        if (isCameraOn) {
            navigator.mediaDevices.getUserMedia({ video: true })
                .then(stream => {
                    streamRef.current = stream;
                    if (videoRef.current) videoRef.current.srcObject = stream;
                    recognitionTimeoutRef.current = window.setTimeout(performAiRecognition, 2000);
                });
        } else {
            if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
            if (recognitionTimeoutRef.current) clearTimeout(recognitionTimeoutRef.current);
        }
        return () => streamRef.current?.getTracks().forEach(t => t.stop());
    }, [isCameraOn]);

    const performAiRecognition = async () => {
        if (!videoRef.current || !canvasRef.current) return;
        setStatus('recognizing');

        const canvas = canvasRef.current;
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
        const base64Image = canvas.toDataURL('image/jpeg').split(',')[1];
        setCapturedImage(canvas.toDataURL('image/jpeg'));

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const prompt = `Identify the person from: ${faces.map(f => f.name).join(', ')}. Return name or 'unknown'.`;
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: base64Image } }, { text: prompt }] }
            });

            const result = response.text?.trim() || 'unknown';
            const match = faces.find(f => f.name.toLowerCase().includes(result.toLowerCase()));

            if (match) {
                setRecognizedFace(match);
                setStatus('recognized');
            } else {
                setStatus('not-found');
            }
        } catch (e) {
            setStatus('idle');
        }
    };

    return (
        <div className="max-w-4xl mx-auto pb-20">
            <div className="glass-card p-8 rounded-[2rem] text-center border border-white/60 mb-8">
                <VideoCameraIcon />
                <h2 className="text-3xl font-bold mt-4">Who's Here?</h2>
                {!isCameraOn ? (
                    <Button onClick={() => setIsCameraOn(true)} className="mt-6 px-10 py-5 text-lg rounded-2xl">Start Looking</Button>
                ) : (
                    <div className="flex flex-col items-center mt-6">
                        <div className="relative w-full max-w-lg aspect-video bg-slate-900 rounded-3xl overflow-hidden border-4 border-white">
                            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                            <canvas ref={canvasRef} className="hidden" />
                            {status === 'recognizing' && <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-white"><SpinnerIcon /> Recognizing...</div>}
                        </div>
                        <Button onClick={() => setIsCameraOn(false)} variant="secondary" className="mt-6 rounded-2xl px-10">Stop Camera</Button>
                    </div>
                )}
            </div>

            <AnimatePresence>
                {status === 'recognized' && recognizedFace && (
                    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-center">
                        <h3 className="text-3xl font-bold text-brand-primary">I remember! This is {recognizedFace.name}</h3>
                        <div className="max-w-xs mx-auto mt-6"><FaceCard face={recognizedFace} role={UserRole.PATIENT} /></div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

