import { GoogleGenAI } from "@google/genai";
import { FaceProfile, Memory, Reminder } from '../types';

export class AIService {
  private static ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  private static model = 'gemini-3-flash-preview';

  /**
   * Generates a response for the patient based on their personal context.
   */
  static async askAssistant(
    query: string, 
    context: { faces: FaceProfile[], memories: Memory[], reminders: Reminder[], userName: string }
  ) {
    const systemInstruction = `
      You are Lucidia, a compassionate AI assistant for ${context.userName}, who has Alzheimer's/Dementia.
      Your goal is to provide comfort, clarity, and memory support.

      CONTEXT:
      - Known People: ${context.faces.map(f => `${f.name} (${f.relation}): ${f.notes}`).join('; ')}
      - Recent Memories: ${context.memories.map(m => `${m.title}: ${m.description}`).join('; ')}
      - Today's Reminders: ${context.reminders.map(r => r.title).join(', ')}

      RULES:
      1. Be extremely patient and kind.
      2. Use short, simple sentences.
      3. If they ask about a person, look them up in the 'Known People' context.
      4. If they seem lost, remind them they are safe at home and their caretaker is nearby.
      5. Never tell them they are "forgetting" or "wrong". Redirect gently.
    `;

    const response = await this.ai.models.generateContent({
      model: this.model,
      contents: query,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text;
  }

  /**
   * Narrates a specific memory for the patient.
   */
  static async narrateMemory(memory: Memory, userName: string) {
    const prompt = `Narrate the following memory for ${userName} in a vivid, nostalgic, and soothing way to help them visualize it: 
    Title: ${memory.title}
    Description: ${memory.description}
    Date: ${memory.date}`;

    const response = await this.ai.models.generateContent({
      model: this.model,
      contents: prompt,
      config: {
        systemInstruction: "You are a gentle storyteller helping a dementia patient recall a happy moment.",
      }
    });

    return response.text;
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuthStore } from '../store/authStore';
import { useFaceStore } from '../store/faceStore';
import { useMemoryStore } from '../store/memoryStore';
import { useReminderStore } from '../store/reminderStore';
import { AIService } from '../services/aiService';
import { SparklesIcon, XMarkIcon, PaperAirplaneIcon, MicrophoneIcon } from './icons/Icons';
import Button from './ui/Button';

const LucidiaAssistant: React.FC = () => {
  const { user } = useAuthStore();
  const { faces } = useFaceStore();
  const { memories } = useMemoryStore();
  const { reminders } = useReminderStore();

  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'ai', text: string}[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!query.trim() || !user) return;

    const userMsg = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const response = await AIService.askAssistant(userMsg, {
        faces,
        memories,
        reminders,
        userName: user.name
      });
      setMessages(prev => [...prev, { role: 'ai', text: response || "I'm here for you, but I didn't quite catch that." }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'ai', text: "I'm having a little trouble connecting right now, but I'm still here." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (user?.role !== 'patient') return null;

  return (
    <div className="fixed bottom-6 right-6 z-50">
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.8, y: 20 }}
            className="mb-4 w-80 md:w-96 h-[500px] glass-card shadow-2xl flex flex-col overflow-hidden bg-white/90 border-brand-primary/20"
          >
            <div className="p-4 bg-brand-primary text-white flex justify-between items-center">
              <div className="flex items-center gap-2">
                <SparklesIcon />
                <span className="font-bold">Lucidia AI</span>
              </div>
              <button onClick={() => setIsOpen(false)}><XMarkIcon /></button>
            </div>

            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/50">
              {messages.length === 0 && (
                <div className="text-center py-10 text-brand-text-light italic">
                  "Who is my daughter?"<br/>
                  "What should I do today?"<br/>
                  "Tell me a story."
                </div>
              )}
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] p-3 rounded-2xl text-sm shadow-sm ${
                    m.role === 'user' ? 'bg-brand-primary text-white rounded-br-none' : 'bg-white text-brand-text border border-slate-100 rounded-bl-none'
                  }`}>
                    {m.text}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                  <div className="bg-white p-3 rounded-2xl rounded-bl-none border border-slate-100">
                    <div className="flex gap-1">
                      <div className="w-1.5 h-1.5 bg-brand-primary rounded-full animate-bounce"></div>
                      <div className="w-1.5 h-1.5 bg-brand-primary rounded-full animate-bounce [animation-delay:0.2s]"></div>
                      <div className="w-1.5 h-1.5 bg-brand-primary rounded-full animate-bounce [animation-delay:0.4s]"></div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="p-4 bg-white border-t border-slate-100 flex gap-2">
              <input
                value={query}
                onChange={e => setQuery(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && handleSend()}
                placeholder="Ask me anything..."
                className="flex-1 bg-slate-50 border-none focus:ring-2 focus:ring-brand-primary rounded-xl px-4 py-2 text-sm"
              />
              <Button onClick={handleSend} className="p-2 min-w-0 rounded-xl">
                <PaperAirplaneIcon />
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <motion.button
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 bg-brand-primary text-white rounded-full shadow-2xl flex items-center justify-center pulse-animation"
      >
        <SparklesIcon />
      </motion.button>
    </div>
  );
};

export default LucidiaAssistant;

import React, { useState, useEffect, useRef } from 'react';
import Sidebar from './Sidebar';
import Navbar from './Navbar';
import Notification from '../ui/Notification';
import LucidiaAssistant from '../LucidiaAssistant';
import { useReminderStore } from '../../store/reminderStore';
import { useGpsStore, isOutsideZone } from '../../store/gpsStore';
import { useAlertStore } from '../../store/alertStore';
import { speak } from '../../utils/helpers';
import { AnimatePresence, motion } from 'framer-motion';

interface MainLayoutProps {
  children: React.ReactNode;
}

const MainLayout: React.FC<MainLayoutProps> = ({ children }) => {
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [activeNotification, setActiveNotification] = useState<string | null>(null);
  const { getDueReminder, markAsNotified } = useReminderStore();

  const { patientLocation, safeZones, updatePatientLocation } = useGpsStore();
  const { addAlert } = useAlertStore();
  const wasOutsideRef = useRef<Set<string>>(new Set());

  useEffect(() => {
    const simulationInterval = setInterval(() => {
      const newLat = patientLocation.location.lat + (Math.random() - 0.5) * 0.0005;
      const newLng = patientLocation.location.lng + (Math.random() - 0.5) * 0.0005;
      updatePatientLocation({ lat: newLat, lng: newLng });

      const currentLoc = { lat: newLat, lng: newLng };
      safeZones.forEach(zone => {
          const isCurrentlyOutside = isOutsideZone(currentLoc, zone);
          const wasPreviouslyOutside = wasOutsideRef.current.has(zone.id);

          if (isCurrentlyOutside && !wasPreviouslyOutside) {
              addAlert({
                  type: 'SafeZoneExit',
                  message: `Patient has left the "${zone.name}" area.`,
              });
              wasOutsideRef.current.add(zone.id);
          } else if (!isCurrentlyOutside && wasPreviouslyOutside) {
              wasOutsideRef.current.delete(zone.id);
          }
      });
    }, 10000); 

    return () => clearInterval(simulationInterval);
  }, [patientLocation, safeZones, updatePatientLocation, addAlert]);

  useEffect(() => {
    const checkReminders = () => {
      const dueReminder = getDueReminder();
      if (dueReminder) {
        const message = `Time for: ${dueReminder.title}`;
        setActiveNotification(message);
        speak(message);
        markAsNotified(dueReminder.id);
      }
    };

    const intervalId = setInterval(checkReminders, 5000);
    return () => clearInterval(intervalId);
  }, [getDueReminder, markAsNotified]);


  return (
    <div className="flex h-screen bg-brand-background text-brand-text">
      <Sidebar isOpen={isSidebarOpen} setIsOpen={setSidebarOpen} />
      <div className="flex-1 flex flex-col overflow-hidden">
        <Navbar onMenuClick={() => setSidebarOpen(!isSidebarOpen)} />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-6 lg:p-8">
            <AnimatePresence mode="wait">
                <motion.div
                    key={window.location.hash}
                    initial={{ opacity: 0, y: 15 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -15 }}
                    transition={{ duration: 0.2 }}
                >
                    {children}
                </motion.div>
            </AnimatePresence>
        </main>

        {/* The AI Assistant remains active for the patient across the entire dashboard */}
        <LucidiaAssistant />

        <AnimatePresence>
            {activeNotification && (
                <Notification
                    message={activeNotification}
                    onClose={() => setActiveNotification(null)}
                />
            )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default MainLayout;

