/**
 * Polling helper for Veo operations
 */
export const pollVideoOperation = async (ai, operation) => {
  let currentOp = operation;
  while (!currentOp.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    currentOp = await ai.operations.getVideosOperation({ operation: currentOp });
  }
  return currentOp;
};

import { GoogleGenAI, Modality } from "@google/genai";
import { FaceProfile, Memory, Reminder } from '../types';

export class AIService {
  private static ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  private static textModel = 'gemini-3-flash-preview';
  private static videoModel = 'veo-3.1-fast-generate-preview';
  private static mapsModel = 'gemini-2.5-flash';

  /**
   * Generates a natural language location summary using Google Maps grounding.
   */
  static async analyzeLocation(lat: number, lng: number, userName: string) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Where is ${userName} right now? Analyze the coordinates ${lat}, ${lng} and tell me what landmarks or places are nearby using Google Maps.`;

    const response = await ai.models.generateContent({
      model: this.mapsModel,
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: lat, longitude: lng }
          }
        }
      },
    });

    const text = response.text;
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return { text, sources };
  }

  /**
   * Initiates a Veo video generation for a memory.
   */
  static async createVideoMemory(memory: Memory) {
    // Note: User must have selected a key for Veo.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `A cinematic, high-quality, nostalgic video recreating this memory: ${memory.title}. ${memory.description}. Soft lighting, warm atmosphere, focused on the emotion of the moment.`;

    let operation = await ai.models.generateVideos({
      model: this.videoModel,
      prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    return operation;
  }

  static async askAssistant(
    query: string, 
    context: { faces: FaceProfile[], memories: Memory[], reminders: Reminder[], userName: string }
  ) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const systemInstruction = `
      You are Lucidia, a compassionate AI assistant for ${context.userName}, who has Alzheimer's/Dementia.
      CONTEXT:
      - People: ${context.faces.map(f => `${f.name} (${f.relation})`).join(', ')}
      - Memories: ${context.memories.map(m => m.title).join(', ')}
      - Reminders: ${context.reminders.map(r => r.title).join(', ')}
      Be patient, kind, and use short sentences.
    `;

    const response = await ai.models.generateContent({
      model: this.textModel,
      contents: query,
      config: { systemInstruction, temperature: 0.7 }
    });

    return response.text;
  }

  static async narrateMemory(memory: Memory, userName: string) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: this.textModel,
      contents: `Narrate this memory for ${userName}: ${memory.title} - ${memory.description}`,
      config: { systemInstruction: "You are a gentle storyteller." }
    });
    return response.text;
  }
}

