  const handleBringToLife = async (memory: any) => {
    // 1. Check for API Key selection (required for Veo)
    if (!(await (window as any).aistudio.hasSelectedApiKey())) {
      await (window as any).aistudio.openSelectKey();
      // Proceed after triggering dialog
    }

    setGeneratingId(memory.id);
    setIsVideoModalOpen(true);
    setVideoUrl(null);
    setGenerationStep('Imagining the scene...');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let operation = await AIService.createVideoMemory(memory);

      const steps = [
        'Sketching the outlines...',
        'Painting the colors of memory...',
        'Adding movement and life...',
        'Almost ready...'
      ];

      let stepIdx = 0;
      while (!operation.done) {
        setGenerationStep(steps[stepIdx % steps.length]);
        stepIdx++;
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await ai.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = (operation as any).response?.generatedVideos?.[0]?.video?.uri;
      const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
      const blob = await response.blob();
      setVideoUrl(URL.createObjectURL(blob));
      setGenerationStep('Memory restored.');
    } catch (e) {
      console.error(e);
      setGenerationStep('Error bringing memory to life.');
    } finally {
      setGeneratingId(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Photo Memories</h1>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {memories.map(m => (
          <div key={m.id} className="glass-card overflow-hidden bg-white/60 flex flex-col group">
            {m.imageUrl && (
                <div className="relative">
                    <img src={m.imageUrl} alt={m.title} className="w-full h-48 object-cover transition-transform group-hover:scale-105" />
                    <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                         <Button 
                            variant="primary" 
                            size="sm" 
                            className="rounded-full shadow-2xl"
                            onClick={() => handleBringToLife(m)}
                         >
                            <VideoCameraIcon /> Bring to Life
                         </Button>
                    </div>
                </div>
            )}
            <div className="p-5 flex-1 flex flex-col">
              <h3 className="font-bold text-xl mb-1">{m.title}</h3>
              <p className="text-xs text-brand-text-light mb-4">{new Date(m.date).toLocaleDateString()}</p>
              <p className="text-brand-text-light text-sm line-clamp-3 mb-4">{m.description}</p>

              <div className="flex gap-2 mt-auto">
                <Button 
                    variant="secondary" 
                    size="sm" 
                    className="flex-1 gap-2"
                    onClick={() => handleNarrate(m)}
                    loading={narratingId === m.id}
                >
                    {!narratingId && <SparklesIcon />}
                    Tell Story
                </Button>
              </div>
            </div>
          </div>
        ))}
        {memories.length === 0 && (
          <div className="col-span-full py-20 text-center text-brand-text-light glass-card bg-white/30">
            <PhotoIcon />
            <p className="mt-4 text-lg">No memories saved yet. Your caretaker can add photos and stories for you.</p>
          </div>
        )}
      </div>

      <Modal isOpen={isVideoModalOpen} onClose={() => setIsVideoModalOpen(false)}>
        <div className="text-center p-4">
          <h2 className="text-2xl font-bold mb-4">Memory Animation</h2>

          {videoUrl ? (
            <div className="space-y-4">
              <video src={videoUrl} controls autoPlay className="w-full rounded-2xl shadow-xl border-4 border-white" />
              <Button onClick={() => setIsVideoModalOpen(false)} className="w-full">Beautiful</Button>
            </div>
          ) : (
            <div className="py-12 flex flex-col items-center">
              <div className="w-20 h-20 mb-6 text-brand-primary animate-pulse">
                <VideoCameraIcon />
              </div>
              <p className="text-xl font-medium text-brand-text mb-2">{generationStep}</p>
              <p className="text-sm text-brand-text-light max-w-xs mx-auto">
                Please wait while we turn this memory into a vivid scene. This takes a few minutes.
              </p>
              <div className="mt-8 w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                <div className="h-full bg-brand-primary animate-[shimmer_2s_infinite] w-full origin-left"></div>
              </div>
            </div>
          )}
        </div>
      </Modal>
    </div>
  );
};

export default MemoriesPage;
